import hashlib
import secrets
from typing import Tuple, List

class Lamport:
    def __init__(self, n: int = 256):
        self.n = n
        self.hash_bytes = n // 8

    def hash(self, data: bytes) -> bytes:
        return hashlib.sha256(data).digest()[:self.hash_bytes]

    def keygen(self) -> Tuple[List[Tuple[bytes, bytes]], List[Tuple[bytes, bytes]]]:
        sk = [(secrets.token_bytes(self.hash_bytes), 
               secrets.token_bytes(self.hash_bytes)) for _ in range(self.n)]
        pk = [(self.hash(sk[i][0]), self.hash(sk[i][1])) for i in range(self.n)]
        return sk, pk

    def sign(self, sk: List[Tuple[bytes, bytes]], msg: bytes) -> List[bytes]:
        h = self.hash(msg)
        sig = []
        for i in range(self.n):
            bit = (h[i // 8] >> (7 - i % 8)) & 1
            sig.append(sk[i][bit])
        return sig

    def verify(self, pk: List[Tuple[bytes, bytes]], msg: bytes, sig: List[bytes]) -> bool:
        h = self.hash(msg)
        for i in range(self.n):
            bit = (h[i // 8] >> (7 - i % 8)) & 1
            if self.hash(sig[i]) != pk[i][bit]:
                return False
        return True

import math
from typing import Dict

class WOTSParams:
    def __init__(self, n: int, w: int):
        self.n = n
        self.w = w

    def calculate(self) -> Dict:
        log_w = int(math.log2(self.w))
        l1 = math.ceil(self.n / log_w)
        l2 = math.floor(math.log2(l1 * (self.w - 1)) / log_w) + 1
        l = l1 + l2

        hash_bytes = self.n // 8

        return {
            'l1': l1,
            'l2': l2,
            'l': l,
            'sk_bytes': l * hash_bytes,
            'pk_bytes': l * hash_bytes,
            'sig_bytes': l * hash_bytes,
            'max_sign_hashes': l * (self.w - 1),
            'max_verify_hashes': l * (self.w - 1)
        }

    @staticmethod
    def compare_w_values(n: int, w_values: list) -> Dict:
        results = {}
        for w in w_values:
            params = WOTSParams(n, w)
            results[f'w={w}'] = params.calculate()
        return results

    @staticmethod
    def find_optimal_w(n: int, max_sig_size: int) -> int:
        for w in [4, 8, 16, 32, 64, 128, 256]:
            params = WOTSParams(n, w)
            calc = params.calculate()
            if calc['sig_bytes'] <= max_sig_size:
                return w
        return 256
